unsafe extern "C" {
    // Safe to call without unsafe block
    pub safe fn sqrt(x: f64) -> f64;
    // Requires unsafe block to call
    pub unsafe fn free(ptr: *mut core::ffi::c_void);
}

// 2024: lifetime 'a is implicitly captured
fn filter<'a>(data: &'a [u8]) -> impl Iterator<Item = &'a u8> {
    data.iter().filter(|b| **b > 0)
}

// Opt out of capturing specific lifetimes:
fn owned_result<'a>(x: &'a str) -> impl Sized + use<> {
    x.to_string()
}

// CORRECT: explicit type annotation
let _: () = fallible_fn()?;
// Or:
fallible_fn::<()>()?;

// CORRECT: explicit return in closure
run(|| -> () { panic!("explicit") });

// WRONG: relies on old () fallback
// fallible_fn()?;  // T inferred as ! in 2024

// WRONG in 2024:
// fn gen() { ... }  // 'gen' is reserved

// CORRECT:
fn generate() { /* renamed from gen */ }
// Or use raw identifier if needed:
fn r#gen() { /* raw identifier escape */ }

let boxed: Box<[u32]> = vec![1, 2, 3].into_boxed_slice();

// 2024: yields owned u32
for val in boxed {
    println!("{val}");  // val: u32
}

// If you need references:
let boxed2: Box<[u32]> = vec![4, 5, 6].into_boxed_slice();
for r in boxed2.iter() {
    println!("{r}");  // r: &u32
}

// CORRECT in 2024:
#[unsafe(no_mangle)]
pub extern "C" fn my_exported_fn() {}

#[unsafe(export_name = "custom_name")]
pub extern "C" fn internal_fn() {}

// WRONG:
// #[no_mangle]  // Error in 2024

use std::ptr::addr_of;
use std::sync::Mutex;

// WRONG: reference to static mut
// static mut COUNTER: u32 = 0;
// let r = unsafe { &COUNTER };  // ERROR

// CORRECT: raw pointer
static mut COUNTER: u32 = 0;
let ptr = unsafe { addr_of!(COUNTER) };

// BETTER: use sync primitives
static COUNTER: Mutex<u32> = Mutex::new(0);

// In Rust 2024: Future and IntoFuture are in prelude
// No need for: use std::future::Future;

async fn process() -> Result<(), Error> {
    let fut = async { compute().await };
    fut.await
}

// IntoFuture enables .await on non-Future types
let result = my_builder.await;  // calls .into_future()
